INSERT IGNORE INTO `chuyen_di` VALUES (1,'Tour Hà Nội 3N2Đ','Tham quan Hồ Gươm, Văn Miếu, Lăng Bác',2500000.00,'2026-05-29','2026-05-31',1,1,1,1,'/anh/chuyendi/hanoi.jpg','Khám phá chiều sâu văn hóa của \"Thủ đô ngàn năm văn hiến\". Quý khách sẽ có những phút giây lắng đọng tại Lăng Bác, tìm hiểu lịch sử tại Văn Miếu - Quốc Tử Giám. Đặc biệt, trải nghiệm Xích lô dạo quanh 36 phố phường vào buổi xế chiều và thưởng thức ẩm thực tinh tế như Phở Thìn, Chả cá Lã Vọng sẽ là ký ức khó quên.',2),(2,'Tour 4N3Đ Đà Nẵng - Hội An','Bà Nà Hill, Hội An cổ',4200000.00,'2026-05-29','2026-05-31',2,2,3,0,'/anh/diemden/danang.jpg','Hành trình xuyên qua những vùng đất di sản. Chạm tay vào \"mây ngàn\" tại Bà Nà Hills với cây Cầu Vàng biểu tượng. Khi màn đêm buông xuống, quý khách sẽ được thả mình vào không gian lung linh của Phố cổ Hội An, tự tay thả hoa đăng trên sông Hoài và thưởng thức show diễn \"Ký ức Hội An\" đẳng cấp thế giới.',1),(3,'Khám phá Huế 2N1Đ','Ăn uống cung đình, sông Hương',1800000.00,'2026-05-29','2026-05-31',3,3,5,0,'/anh/diemden/hue.jpg','Trở về không gian triều đình phong kiến với hệ thống Đại Nội và các lăng tẩm uy nghi (Lăng Tự Đức, Khải Định). Điểm khác biệt chính là trải nghiệm Nghe ca Huế trên sông Hương và thưởng thức \"Cơm Vua\" - nơi quý khách được hóa thân thành hoàng thân quốc thích trong bộ lễ phục triều đình.',1),(4,'Hạ Long Bay 2N1Đ','Du thuyền Vịnh Hạ Long',3000000.00,'2026-05-29','2026-05-31',4,3,6,0,'/anh/diemden/halong.jpg','Tận hưởng kỳ nghỉ dưỡng thượng lưu trên Du thuyền 5 sao. Quý khách sẽ được chèo thuyền Kayak xuyên qua các hang động đá vôi nghìn năm tuổi, đón bình minh với bài tập Tai-chi trên boong tàu và thưởng thức tiệc hải sản tươi sống giữa lòng di sản thiên nhiên thế giới.',1),(5,'Nha Trang Beach Relax 3N','Tắm biển, lặn ngắm san hô',3500000.00,'2026-05-29','2026-05-31',5,3,7,0,'/anh/diemden/nhatrang.jpg','Sự kết hợp hoàn hảo giữa nhịp sống phố thị và sự tĩnh lặng của biển khơi. Tour tập trung vào việc tối ưu thời gian để quý khách vừa có thể check-in những biểu tượng của Thủ đô, vừa kịp lúc bắt trọn khoảnh khắc hoàng hôn buông trên vịnh biển từ những góc nhìn đẹp nhất.',1),(6,'Phú Quốc Resort 4N','Resort 5*, câu cá, lặn',7000000.00,'2026-05-29','2026-05-31',6,9,8,0,'/anh/diemden/hue.jpg','Nghỉ dưỡng tại những bãi cát trắng mịn nhất Việt Nam. Chương trình tập trung vào trải nghiệm cá nhân hóa tại VinWonders, tắm bùn khoáng nóng thư giãn phục hồi sức khỏe và tham gia các trò chơi thể thao nước cảm giác mạnh như dù lượn, lặn ngắm san hô tại Vịnh San Hô.',1),(7,'Sa Pa Trek 2N','Trekking bản làng, cáp treo',2000000.00,'2026-05-29','2026-05-31',7,7,9,0,'/anh/diemden/sapa.jpg','Một hành trình nghỉ dưỡng thực thụ tại các resort cao cấp. Điểm nhấn là chuyến Cáp treo vượt biển dài nhất thế giới đi hòn Thơm, khám phá \"Thành phố không ngủ\" Grand World và thưởng thức đặc sản bún quậy trứ danh cùng rượu sim nồng nàn.',1),(8,'Cần Thơ Miền Tây 2N1Đ','Chợ nổi, miệt vườn',1600000.00,'2026-05-29','2026-05-31',8,7,10,0,'/anh/diemden/cantho.jpg','Sự giao thoa giữa hai vùng biển đẹp nhất Việt Nam. Quý khách sẽ thấy được sự khác biệt giữa vẻ đẹp hiện đại, năng động của Đà Nẵng và nét hoang sơ, thơ mộng của Phú Quốc. Đây là tour dành cho những tín đồ \"cuồng biển\" muốn chinh phục mọi cung đường xanh.',1),(9,'Beijing City Tour 4N','Tường thành, Tử Cấm Thành',1650000.00,'2026-05-29','2026-05-31',9,5,11,0,'/anh/diemden/thuonghai.jpg','Chạm tay vào kỳ quan Vạn Lý Trường Thành, khám phá sự huyền bí của Tử Cấm Thành và thưởng thức món Vịt quay Bắc Kinh nguyên bản trong không gian cung đình xưa.',1),(10,'Shanghai Highlights 3N','Tham quan Thượng Hải, Bến Thượng Hải',1300000.00,'2026-05-29','2026-05-31',10,5,12,1,'/anh/chuyendi/shanghai.jpg','Tập trung vào nhịp sống sôi động bậc nhất Trung Hoa. Dạo bước trên phố đi bộ Nam Kinh, chiêm bái Dự Viên và tận hưởng sự lộng lẫy của các tòa nhà chọc trời về đêm.',1),(11,'Zhangjiajie Nature 3N','Thiên nhiên Trương Gia Giới',1800000.00,'2026-05-29','2026-05-31',11,5,13,0,'/anh/diemden/hue.jpg','Lạc vào hành tinh Pandora ngoài đời thực với các cột đá cao vút tại Viên Gia Giới. Trải nghiệm cảm giác mạnh trên Cầu kính Đại Hiệp Cốc và đi thang máy Bách Lộ dài nhất thế giới.',1),(12,'Tokyo Family 5N','Tokyo Disneyland, Asakusa',2000000.00,'2026-05-29','2026-05-31',12,6,14,0,'/anh/diemden/tokyo.jpg','Tour lý tưởng cho gia đình. Khám phá Disneyland thần tiên, giao lộ Shibuya sầm uất và trải nghiệm văn hóa Anime tại Akihabara cùng với hoạt động làm Sushi thủ công.',1),(13,'Kyoto Culture 3N','Đền chùa, trà đạo',1800000.00,'2026-05-29','2026-05-31',13,6,14,0,'/anh/diemden/kyoto.jpg','Tìm về sự an yên tại các ngôi đền nghìn năm tuổi như Thanh Thủy Tự (Kiyomizu-dera). Điểm nhấn là đi bộ dưới hàng ngàn cổng Torii đỏ rực tại Fushimi Inari và gặp gỡ các nàng Geisha tại phố Gion.',1),(14,'Osaka Food Tour 2N','Món ăn đường phố, Dotonbori',1700000.00,'2026-05-29','2026-05-31',14,6,14,0,'/anh/diemden/osaka.jpg','Thiên đường cho những tín đồ ẩm thực. Càn quét khu phố Dotonbori với Takoyaki, Okonomiyaki. Tham quan lâu đài Osaka uy nghiêm và khu vui chơi Universal Studios.',1),(15,'Seoul City 4N','Mua sắm Myeongdong, palaces',2800000.00,'2026-05-29','2026-05-31',15,8,15,0,'/anh/diemden/seoul.jpg','Khám phá \"Làn sóng Hallyu\" tại thủ đô Hàn Quốc. Mặc Hanbok check-in cung điện Gyeongbokgung, mua sắm tại Myeongdong và ngắm toàn cảnh thành phố từ tháp Namsan lãng mạn.',1),(16,'Hà Nội - Hạ Long 2N','Combo Hà Nội + Hạ Long',3200000.00,'2026-05-29','2026-05-31',4,3,6,0,'/anh/diemden/hanoi.jpg','Sự giao thoa giữa hai vùng biển đẹp nhất Việt Nam. Quý khách sẽ thấy được sự khác biệt giữa vẻ đẹp hiện đại, năng động của Đà Nẵng và nét hoang sơ, thơ mộng của Phú Quốc. Đây là tour dành cho những tín đồ \"cuồng biển\" muốn chinh phục mọi cung đường xanh.',1),(17,'Đà Nẵng - Phú Quốc 5N','Đà Nẵng + Phú Quốc nghỉ dưỡng',9000000.00,'2026-05-29','2026-05-31',6,2,8,0,'/anh/diemden/phuquoc.jpg','Sự giao thoa giữa hai vùng biển đẹp nhất Việt Nam. Quý khách sẽ thấy được sự khác biệt giữa vẻ đẹp hiện đại, năng động của Đà Nẵng và nét hoang sơ, thơ mộng của Phú Quốc. Đây là tour dành cho những tín đồ \"cuồng biển\" muốn chinh phục mọi cung đường xanh.',1),(18,'Tour Bắc Kinh - Thượng Hải 7N','Kết hợp Bắc Kinh và Thượng Hải',2200000.00,'2026-05-29','2026-05-31',9,5,12,1,'/anh/chuyendi/backinh.jpg','Hành trình kết nối giữa quá khứ và tương lai. Từ vẻ cổ kính của cung điện Bắc Kinh đến sự xa hoa, hiện đại của Bến Thượng Hải và tháp truyền hình Minh Châu Phương Đông.',1);
